def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def check_primes():
    for p in range(2, 1000):  # Check for primes up to 1000
        if is_prime(p):
            q = 8 * p**2 + 1
            if is_prime(q):
                print(f"p = {p}, 8p^2 + 1 = {q} are both prime.")
            else:
                print(f"p = {p} is prime, but 8p^2 + 1 = {q} is not prime.")

